import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),o={name:"guide/getting-started.md"};function i(n,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><h2 id="what-is-insposearch" tabindex="-1">What is InspoSearch <a class="header-anchor" href="#what-is-insposearch" aria-label="Permalink to &quot;What is InspoSearch&quot;">​</a></h2><p>InspoSearch is an open-source visual research engine. It searches <strong>2,400+ cultural heritage sources</strong> — museums, archives, national libraries, photo agencies, scientific illustration collections — through a single search bar and normalises every response into the same shape.</p><p>The app runs in the browser. No account, no tracking, no search backend — your browser talks to each source API directly. A small Cloudflare Worker handles only what the browser can&#39;t: proxying CORS-walled APIs, running the free-tier AI analysis (Workers AI), and storing shared boards for 30 days. Optional API keys stay in <code>localStorage</code> on your machine and are sent only to the provider they belong to.</p><p><span class="custom-badge">AGPL-3.0</span> · <strong>Current version:</strong> 1.1.0 · <strong>Try it:</strong> <a href="https://insposearch.pages.dev" target="_blank" rel="noreferrer">insposearch.pages.dev</a></p><h2 id="the-30-second-tour" tabindex="-1">The 30-second tour <a class="header-anchor" href="#the-30-second-tour" aria-label="Permalink to &quot;The 30-second tour&quot;">​</a></h2><ol><li>Go to <a href="https://insposearch.pages.dev" target="_blank" rel="noreferrer">insposearch.pages.dev</a></li><li>Type a query — <code>vermeer</code>, <code>ukiyo-e</code>, <code>brutalist architecture</code>, <code>medieval bestiary</code></li><li>Press <code>Enter</code>. Results stream in as each source responds</li><li>Scroll. More results load automatically — past page 5, the 3-lane dispatcher keeps variety up</li><li>Click any image for full metadata, the original source link, deep zoom (if IIIF), and AI analysis</li></ol><p>That&#39;s the loop. Everything else is sharpening it.</p><h2 id="running-locally" tabindex="-1">Running locally <a class="header-anchor" href="#running-locally" aria-label="Permalink to &quot;Running locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/GI-Synth/InspoSearch.git</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> InspoSearch</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # bundles src/ → insposearch/app.js</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # serves at http://localhost:3000</span></span></code></pre></div><p>No runtime dependencies. The build step bundles 6 ES modules with esbuild and that&#39;s it.</p><h2 id="search-modes" tabindex="-1">Search modes <a class="header-anchor" href="#search-modes" aria-label="Permalink to &quot;Search modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Best for</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Exact</strong></td><td>Known subjects, specific artists, named works</td><td>Matches your terms precisely across title / artist / description / tags. Diacritic-aware (<code>van gogh</code> finds <code>Van Gogh</code>)</td></tr><tr><td><strong>Explore</strong></td><td>Visual discovery, mood boards, open-ended research</td><td>Casts wider — synonym expansion, qualifier rotation, relaxed source filters</td></tr></tbody></table><p>Toggle with <code>m</code> or the mode switcher in the search bar.</p><h2 id="features-worth-knowing" tabindex="-1">Features worth knowing <a class="header-anchor" href="#features-worth-knowing" aria-label="Permalink to &quot;Features worth knowing&quot;">​</a></h2><h3 id="board-view-b" tabindex="-1">Board view (<code>b</code>) <a class="header-anchor" href="#board-view-b" aria-label="Permalink to &quot;Board view (`b`)&quot;">​</a></h3><p>Pin images to a freeform canvas. Drag, group, compare side by side. Persisted to <code>localStorage</code>; optionally shared via a 30-day KV link.</p><h3 id="deep-zoom" tabindex="-1">Deep zoom <a class="header-anchor" href="#deep-zoom" aria-label="Permalink to &quot;Deep zoom&quot;">​</a></h3><p>Any IIIF-compatible source opens in an OpenSeadragon viewer. Pan and zoom to brushstroke resolution. Mouse wheel + click-drag, or keyboard.</p><h3 id="colour-extraction" tabindex="-1">Colour extraction <a class="header-anchor" href="#colour-extraction" aria-label="Permalink to &quot;Colour extraction&quot;">​</a></h3><p>Dominant colours are computed on every result. Filter or sort the entire grid by palette — useful when you&#39;re looking for visual relationships rather than subject matches.</p><h3 id="_3d-constellation" tabindex="-1">3D constellation <a class="header-anchor" href="#_3d-constellation" aria-label="Permalink to &quot;3D constellation&quot;">​</a></h3><p>Renders results as a navigable point cloud arranged by visual similarity. Surfaces connections the grid hides.</p><h3 id="interpret-cross-reference-i" tabindex="-1">Interpret / cross-reference (<code>i</code>) <a class="header-anchor" href="#interpret-cross-reference-i" aria-label="Permalink to &quot;Interpret / cross-reference (`i`)&quot;">​</a></h3><p>Select any image → InspoSearch cross-references it against every source. Finds related works, traces provenance, builds context in one pass.</p><h3 id="ai-analysis-—-no-keys-required" tabindex="-1">AI analysis — no keys required <a class="header-anchor" href="#ai-analysis-—-no-keys-required" aria-label="Permalink to &quot;AI analysis — no keys required&quot;">​</a></h3><p>Default analysis runs on <strong>Cloudflare Workers AI (LLaVA 1.5)</strong> — zero setup. Bring your own key for Gemini, Claude, OpenAI, or Ollama if you want to override. See <a href="/docs/guide/api-keys">API Keys</a>.</p><h3 id="offline-caching" tabindex="-1">Offline caching <a class="header-anchor" href="#offline-caching" aria-label="Permalink to &quot;Offline caching&quot;">​</a></h3><p>Previously loaded images and metadata are cached via the service worker. Recent searches remain browsable without a connection.</p><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>/</code></td><td>Focus search bar</td></tr><tr><td><code>Enter</code></td><td>Execute search</td></tr><tr><td><code>Esc</code></td><td>Close overlay / clear focus</td></tr><tr><td><code>←</code> <code>→</code></td><td>Navigate images in detail view</td></tr><tr><td><code>↑</code> <code>↓</code></td><td>Scroll results grid</td></tr><tr><td><code>m</code></td><td>Switch mode (exact / explore)</td></tr><tr><td><code>i</code></td><td>Interpret selected image</td></tr><tr><td><code>b</code></td><td>Toggle board view</td></tr><tr><td><code>s</code></td><td>Toggle source filter sidebar</td></tr><tr><td><code>k</code></td><td>Toggle API keys panel</td></tr><tr><td><code>t</code></td><td>Scroll to top</td></tr></tbody></table><h2 id="source-categories" tabindex="-1">Source categories <a class="header-anchor" href="#source-categories" aria-label="Permalink to &quot;Source categories&quot;">​</a></h2><p>InspoSearch organises sources into eight categories. Counts include dynamically-discovered Europeana and DPLA providers.</p><table tabindex="0"><thead><tr><th>Category</th><th>Contains</th></tr></thead><tbody><tr><td>Museums</td><td>Major and regional museums, including IIIF-native collections</td></tr><tr><td>Historical</td><td>National libraries, archives, digital heritage aggregators</td></tr><tr><td>Art and Design</td><td>Illustration archives, design collections, typography</td></tr><tr><td>Photography</td><td>Press archives, photo agencies, stock providers</td></tr><tr><td>Nature</td><td>Natural history, botanical, biodiversity</td></tr><tr><td>Maps</td><td>Cartographic collections, historical atlases</td></tr><tr><td>Fashion</td><td>Costume archives, textile design, fashion photography</td></tr><tr><td>Science</td><td>Scientific illustration, medical archives, astronomy</td></tr></tbody></table><p>See the <a href="/docs/guide/sources">Sources</a> page for the full directory.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/docs/guide/sources">Sources</a> — complete source directory</li><li><a href="/docs/guide/api-keys">API Keys</a> — which sources need keys, and why most don&#39;t</li><li><a href="/docs/reference/architecture">Architecture</a> — how the engine works under the hood</li><li><a href="/docs/about/contributing">Contributing</a> — add a source, fix a bug, improve docs</li></ul>',37)])])}const g=t(o,[["render",i]]);export{u as __pageData,g as default};
